sql:
SELECT avg_flow
FROM flow_data
WHERE date_id = 1;

SELECT avg_flow AS average_flow_rate
FROM flow_data
WHERE flow_id = 0 AND date_id = 1;

SELECT DISTINCT flow_id
FROM flow_data_trends
WHERE trend_type IN ('increasing flow rate', 'decreasing flow rate');

SELECT avg_flow, std
FROM flow_data
WHERE flow_id = 0;

SELECT avg_flow, std 
FROM flow_data 
WHERE flow_id = 1 AND date_id = 1;

SELECT avg_flow, flow_type
FROM flow_data
ORDER BY avg_flow DESC;

external_knowledge:
- "notably rising" refers to the trend type 'increasing flow rate';
- "a certain significant threshold" in this context means an average flow rate greater than 50;
- "measurement units" and "trend indications" refer to `flow_rate_unit` and `trend_type`, respectively.

sql:
SELECT flow_id, avg_flow, std, dif_flow_id_day_week
FROM flow_data
ORDER BY avg_flow DESC;

SELECT COUNT(*) AS high_severity_count
FROM flow_data_anomalies
WHERE severity = 'high';

SELECT AVG(avg_flow) AS average_flow_rate, flow_rate_unit
FROM flow_data
LIMIT 1;

SELECT 
    (SELECT AVG(avg_flow) FROM flow_data) AS AvgFlowRate,
    (SELECT COUNT(anomaly_id) FROM flow_data_anomalies) AS AnomalyCount;

SELECT AVG(avg_flow) AS average_flow_rate
FROM flow_data
WHERE flow_id = 0;

SELECT COUNT(*)
FROM flow_data
WHERE avg_flow > (SELECT AVG(avg_flow) FROM flow_data);
